declare module '*.css' {
  const content: string;
  export default content;
}

declare module '@fontsource/*' {
  const value: string;
  export default value;
}

declare module '@fontsource/nunito/400.css' { const value: string; export default value; }
declare module '@fontsource/nunito/600.css' { const value: string; export default value; }
declare module '@fontsource/nunito/700.css' { const value: string; export default value; }
declare module '@fontsource/nunito/800.css' { const value: string; export default value; }
declare module '@fontsource/inter/400.css' { const value: string; export default value; }
declare module '@fontsource/inter/600.css' { const value: string; export default value; }
